const input = $input.first().json;
const action = input.action || 'search_station';
const BASE = 'https://v6.db.transport.rest';

async function resolveStation(nameOrId) {
  if (/^\d+$/.test(nameOrId)) return nameOrId;
  const res = await helpers.httpRequest({
    method: 'GET',
    url: BASE + '/locations?query=' + encodeURIComponent(nameOrId) + '&results=1'
  });
  if (!res || res.length === 0) return null;
  return res[0].id;
}

function fmtTime(iso) {
  if (!iso) return '?';
  return iso.substring(11, 16);
}

function fmtDelay(delay) {
  if (!delay && delay !== 0) return '';
  const min = Math.round(delay / 60);
  if (min <= 0) return '';
  return ' +' + min + 'min';
}

function fmtDuration(dep, arr) {
  if (!dep || !arr) return '?';
  const ms = new Date(arr) - new Date(dep);
  const h = Math.floor(ms / 3600000);
  const m = Math.round((ms % 3600000) / 60000);
  return h > 0 ? h + 'h' + (m > 0 ? m + 'min' : '') : m + 'min';
}

// === search_station ===
if (action === 'search_station') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];

  try {
    const res = await helpers.httpRequest({
      method: 'GET',
      url: BASE + '/locations?query=' + encodeURIComponent(query) + '&results=5'
    });
    if (!res || res.length === 0) {
      return [{ json: { result: 'No stations found for: ' + query } }];
    }
    let result = 'Stations for "' + query + '":\n\n';
    for (const s of res) {
      result += '- ' + s.name + ' (ID: ' + s.id + ')';
      if (s.products) {
        const types = [];
        if (s.products.nationalExpress || s.products.national) types.push('ICE/IC');
        if (s.products.regionalExpress || s.products.regional) types.push('RE/RB');
        if (s.products.suburban) types.push('S');
        if (s.products.subway) types.push('U');
        if (s.products.tram) types.push('Tram');
        if (s.products.bus) types.push('Bus');
        if (types.length > 0) result += ' [' + types.join(', ') + ']';
      }
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Station search failed: ' + err.message } }];
  }

// === get_departures ===
} else if (action === 'get_departures') {
  const station = input.station;
  if (!station) return [{ json: { error: 'Parameter "station" is required (name or ID).' } }];

  try {
    const stationId = await resolveStation(station);
    if (!stationId) return [{ json: { error: 'Station not found: ' + station } }];

    const duration = parseInt(input.duration) || 60;
    const res = await helpers.httpRequest({
      method: 'GET',
      url: BASE + '/stops/' + stationId + '/departures?duration=' + duration + '&results=10'
    });
    const deps = res.departures || [];
    if (deps.length === 0) {
      return [{ json: { result: 'No departures found.' } }];
    }

    let result = 'Departures from ' + (deps[0].stop?.name || station) + ':\n\n';
    for (const d of deps) {
      const time = fmtTime(d.when || d.plannedWhen);
      const delay = fmtDelay(d.delay);
      const line = d.line?.name || '?';
      const dir = d.direction || '?';
      const pl = d.platform || d.plannedPlatform || '?';
      const cancelled = d.cancelled ? ' [CANCELLED]' : '';
      result += time + delay + ' | ' + line + ' → ' + dir + ' | Gl.' + pl + cancelled + '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Departures failed: ' + err.message } }];
  }

// === get_arrivals ===
} else if (action === 'get_arrivals') {
  const station = input.station;
  if (!station) return [{ json: { error: 'Parameter "station" is required (name or ID).' } }];

  try {
    const stationId = await resolveStation(station);
    if (!stationId) return [{ json: { error: 'Station not found: ' + station } }];

    const duration = parseInt(input.duration) || 60;
    const res = await helpers.httpRequest({
      method: 'GET',
      url: BASE + '/stops/' + stationId + '/arrivals?duration=' + duration + '&results=10'
    });
    const arrs = res.arrivals || [];
    if (arrs.length === 0) {
      return [{ json: { result: 'No arrivals found.' } }];
    }

    let result = 'Arrivals at ' + (arrs[0].stop?.name || station) + ':\n\n';
    for (const a of arrs) {
      const time = fmtTime(a.when || a.plannedWhen);
      const delay = fmtDelay(a.delay);
      const line = a.line?.name || '?';
      const from = a.provenance || '?';
      const pl = a.platform || a.plannedPlatform || '?';
      const cancelled = a.cancelled ? ' [CANCELLED]' : '';
      result += time + delay + ' | ' + line + ' from ' + from + ' | Gl.' + pl + cancelled + '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Arrivals failed: ' + err.message } }];
  }

// === search_journey ===
} else if (action === 'search_journey') {
  const from = input.from;
  const to = input.to;
  if (!from || !to) return [{ json: { error: 'Parameters "from" and "to" are required (station name or ID).' } }];

  try {
    const fromId = await resolveStation(from);
    const toId = await resolveStation(to);
    if (!fromId) return [{ json: { error: 'Origin station not found: ' + from } }];
    if (!toId) return [{ json: { error: 'Destination station not found: ' + to } }];

    let url = BASE + '/journeys?from=' + fromId + '&to=' + toId;
    const results = parseInt(input.results) || 3;
    url += '&results=' + results;
    if (input.departure) url += '&departure=' + encodeURIComponent(input.departure);

    const res = await helpers.httpRequest({ method: 'GET', url });
    const journeys = res.journeys || [];
    if (journeys.length === 0) {
      return [{ json: { result: 'No connections found.' } }];
    }

    let result = 'Connections ' + from + ' → ' + to + ':\n\n';
    for (let i = 0; i < journeys.length; i++) {
      const j = journeys[i];
      const legs = j.legs || [];
      const firstLeg = legs[0];
      const lastLeg = legs[legs.length - 1];
      const dep = fmtTime(firstLeg?.departure || firstLeg?.plannedDeparture);
      const arr = fmtTime(lastLeg?.arrival || lastLeg?.plannedArrival);
      const dur = fmtDuration(
        firstLeg?.departure || firstLeg?.plannedDeparture,
        lastLeg?.arrival || lastLeg?.plannedArrival
      );
      const transfers = legs.filter(l => l.line).length - 1;

      result += (i + 1) + ') ' + dep + ' → ' + arr + ' | ' + dur;
      if (transfers > 0) result += ' | ' + transfers + 'x umsteigen';
      result += '\n';

      for (const leg of legs) {
        if (leg.walking) {
          result += '   🚶 Walk';
          if (leg.distance) result += ' (' + leg.distance + 'm)';
          result += '\n';
          continue;
        }
        const lDep = fmtTime(leg.departure || leg.plannedDeparture);
        const lArr = fmtTime(leg.arrival || leg.plannedArrival);
        const lDelay = fmtDelay(leg.departureDelay);
        const line = leg.line?.name || '?';
        const orig = leg.origin?.name || '?';
        const dest = leg.destination?.name || '?';
        const plDep = leg.departurePlatform || leg.plannedDeparturePlatform || '?';
        const plArr = leg.arrivalPlatform || leg.plannedArrivalPlatform || '?';
        result += '   ' + lDep + lDelay + ' ' + orig + ' Gl.' + plDep + ' → ' + lArr + ' ' + dest + ' Gl.' + plArr + ' | ' + line + '\n';
      }
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Journey search failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use search_station, get_departures, get_arrivals, or search_journey.' } }];
}
